            Err(pos) => pos,
        };

        let j = if j >= n { n - 1 } else { j };
        if nums[j] > max_val_threshold {
            if j == 0 {
                continue;
            }
            let current_j = j - 1;
            let elements_to_keep = (current_j - i + 1) as i64;
            let removal = n as i64 - elements_to_keep;
            if removal < min_removal {
                min_removal = removal;
            }
        } else {
            let elements_to_keep = (j - i + 1) as i64;
            let removal = n as i64 - elements_to_keep;
            if removal < min_removal {
                min_removal = removal;
            }
        }
    }

